import React from 'react';
import { useSettingsStore } from '../store/useSettingsStore';

export const RunningText: React.FC = () => {
  const { runningText } = useSettingsStore();

  return (
    <div className="w-full overflow-hidden whitespace-nowrap py-3 bg-[#1D2B57] min-h-[50px] flex items-center border-t-4 border-[#D4AF37]">
      <div className="inline-block animate-[marquee_25s_linear_infinite] pl-[100%] text-xl font-medium tracking-wide text-white">
        {runningText}
      </div>
    </div>
  );
};
