import { useMemo } from 'react';
import { Coordinates, CalculationMethod, PrayerTimes, Madhab } from 'adhan';
import { useSettingsStore } from '../store/useSettingsStore';
import { addMinutes } from 'date-fns';

export const usePrayerTimes = () => {
  const { latitude, longitude, calculationMethod, madhab, offsets } = useSettingsStore();

  const today = useMemo(() => {
    const coords = new Coordinates(latitude, longitude);
    const date = new Date();
    
    // Map calculation method string to Adhan object
    let params = CalculationMethod.Singapore();
    if (calculationMethod === 'MuslimWorldLeague') params = CalculationMethod.MuslimWorldLeague();
    if (calculationMethod === 'Egyptian') params = CalculationMethod.Egyptian();
    
    params.madhab = madhab === 'hanafi' ? Madhab.Hanafi : Madhab.Shafi;

    const prayerTimes = new PrayerTimes(coords, date, params);

    // Apply offsets (in minutes)
    // Note: Adhan returns Date objects, we can manipulate them
    // But Adhan doesn't have direct 'offset' method on the instance for all prayers easily accessible via the property access
    // We will wrap the times
    
    return {
      fajr: addMinutes(prayerTimes.fajr, offsets.subuh),
      sunrise: addMinutes(prayerTimes.sunrise, offsets.syuruq),
      dhuhr: addMinutes(prayerTimes.dhuhr, offsets.dzuhur),
      asr: addMinutes(prayerTimes.asr, offsets.ashar),
      maghrib: addMinutes(prayerTimes.maghrib, offsets.maghrib),
      isha: addMinutes(prayerTimes.isha, offsets.isya),
      
      // Helper to find next prayer
      timeForPrayer: (prayer: string) => {
        const times = {
            fajr: addMinutes(prayerTimes.fajr, offsets.subuh),
            sunrise: addMinutes(prayerTimes.sunrise, offsets.syuruq),
            dhuhr: addMinutes(prayerTimes.dhuhr, offsets.dzuhur),
            asr: addMinutes(prayerTimes.asr, offsets.ashar),
            maghrib: addMinutes(prayerTimes.maghrib, offsets.maghrib),
            isha: addMinutes(prayerTimes.isha, offsets.isya),
        };
        return times[prayer as keyof typeof times];
      }
    };
  }, [latitude, longitude, calculationMethod, madhab, offsets]);

  // Logic to determine current and next prayer
  const now = new Date();
  let nextPrayer = null;
  let currentPrayer = null;
  
  const times = [
    { name: 'fajr', time: today.fajr },
    { name: 'sunrise', time: today.sunrise },
    { name: 'dhuhr', time: today.dhuhr },
    { name: 'asr', time: today.asr },
    { name: 'maghrib', time: today.maghrib },
    { name: 'isha', time: today.isha },
  ];

  // Find next
  for (const p of times) {
    if (p.time > now) {
      nextPrayer = p;
      break;
    }
  }
  
  // If no next prayer today, it's Fajr tomorrow (simplified)
  if (!nextPrayer) {
      nextPrayer = { name: 'fajr', time: addMinutes(today.fajr, 24 * 60), isTomorrow: true };
  }

  // Find current
  // ... (simplified for now)

  return { today, nextPrayer, currentPrayer };
};
