import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export interface PrayerOffsets {
  subuh: number;
  syuruq: number;
  dzuhur: number;
  ashar: number;
  maghrib: number;
  isya: number;
}

export interface AppSettings {
  mosqueName: string;
  mosqueAddress: string;
  latitude: number;
  longitude: number;
  calculationMethod: string;
  madhab: 'shafi' | 'hanafi';
  offsets: PrayerOffsets;
  
  iqamahDuration: number; // General duration (minutes)
  iqamahDurationSubuh: number; // Specific for Subuh (minutes)
  prayerDuration: number; // Duration for Prayer Break (minutes)
  
  showHijri: boolean;
  contentSource: 'youtube' | 'images' | 'off';
  youtubePlaylistId: string;
  runningText: string;
  
  // Slide Settings
  posterKhotibImage: string | null;
  posterKajianImage: string | null;
  showSlideKhotib: boolean;
  showSlideKajian: boolean;
}

interface SettingsState extends AppSettings {
  updateSettings: (settings: Partial<AppSettings>) => void;
  updateOffsets: (offsets: Partial<PrayerOffsets>) => void;
}

const defaultSettings: AppSettings = {
  mosqueName: 'Masjid Abu Bakar Ash-Shiddiq',
  mosqueAddress: 'Lembang, Bandung Barat',
  latitude: -6.8157,
  longitude: 107.6191,
  calculationMethod: 'Singapore',
  madhab: 'shafi',
  offsets: {
    subuh: 2,
    syuruq: -2,
    dzuhur: 2,
    ashar: 2,
    maghrib: 2,
    isya: 2,
  },
  
  iqamahDuration: 10, // Default 10 mins for others
  iqamahDurationSubuh: 20, // Default 20 mins for Subuh
  prayerDuration: 25, // Default 25 mins for Prayer Break (Sholat berlangsung)
  
  showHijri: true,
  contentSource: 'youtube',
  youtubePlaylistId: '4njn5YLk4uw', 
  runningText: 'Selamat datang di Masjid Abu Bakar Ash-Shiddiq - AIS Al-Amanah Islamic School. Mohon luruskan dan rapatkan shaf.',
  
  // Default Slide Settings
  posterKhotibImage: null,
  posterKajianImage: null,
  showSlideKhotib: true,
  showSlideKajian: true,
};

export const useSettingsStore = create<SettingsState>()(
  persist(
    (set) => ({
      ...defaultSettings,
      updateSettings: (newSettings) =>
        set((state) => ({ ...state, ...newSettings })),
      updateOffsets: (newOffsets) =>
        set((state) => ({
          ...state,
          offsets: { ...state.offsets, ...newOffsets },
        })),
    }),
    {
      name: 'jadwal-shalat-settings-v12', // Bump version for video fix final
    }
  )
);
