import moment from 'moment-hijri';
import { useSettingsStore } from '../store/useSettingsStore';

export const useHijriDate = (date: Date) => {
  const { showHijri } = useSettingsStore();
  
  if (!showHijri) return '';

  const m = moment(date);
  m.locale('en'); // or id
  return `${m.iDate()} ${m.iMonth()} ${m.iYear()} H`;
};
