import React from 'react';
import { cn } from '../lib/utils';

export type PrayerStatus = 'normal' | 'adzan' | 'iqamah' | 'sholat';

interface StatusOverlayProps {
  status: PrayerStatus;
  prayerName: string;
  iqamahCountdown: number;
}

export const StatusOverlay: React.FC<StatusOverlayProps> = ({ status, prayerName, iqamahCountdown }) => {
  if (status === 'normal') return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black/90 flex flex-col items-center justify-center text-white p-10 animate-in fade-in duration-500">
      
      {status === 'adzan' && (
        <div className="text-center animate-pulse">
          <h1 className="text-6xl font-bold mb-4 text-mosque-gold">ADZAN {prayerName}</h1>
          <p className="text-2xl opacity-80">Saatnya menunaikan ibadah sholat {prayerName}</p>
        </div>
      )}

      {status === 'iqamah' && (
        <div className="text-center">
          <h1 className="text-4xl font-bold mb-8 text-mosque-green">IQAMAH {prayerName}</h1>
          <div className="text-[10rem] font-bold font-mono leading-none text-white tabular-nums">
            {Math.floor(iqamahCountdown / 60)}:{String(iqamahCountdown % 60).padStart(2, '0')}
          </div>
          <p className="text-xl mt-4 opacity-70">Menuju pelaksanaan sholat berjamaah</p>
        </div>
      )}

      {status === 'sholat' && (
        <div className="text-center">
          <h1 className="text-5xl font-bold mb-6">SHOLAT {prayerName} SEDANG BERLANGSUNG</h1>
          <div className="flex gap-4 justify-center text-gray-400">
            <span className="bg-gray-800 px-4 py-2 rounded-full">Mohon Nonaktifkan HP</span>
            <span className="bg-gray-800 px-4 py-2 rounded-full">Luruskan Shaf</span>
          </div>
        </div>
      )}
    </div>
  );
};
