import React from 'react';
import { useSettingsStore } from '../store/useSettingsStore';
import { useClock } from '../hooks/useClock';
import { useHijriDate } from '../hooks/useHijriDate';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';
import { Phone, Mail, Facebook, Instagram, Youtube } from 'lucide-react';

export const Header: React.FC = () => {
  const { mosqueName, mosqueAddress } = useSettingsStore();
  const now = useClock();
  const hijriDate = useHijriDate(now);

  return (
    <div className="flex flex-col shadow-xl z-50 relative">
      {/* Top Utility Bar */}
      <div className="bg-white border-b border-gray-100 py-1 px-6 flex justify-between items-center text-xs md:text-sm text-[#1D2B57] font-medium">
        <div className="flex gap-4">
           <span className="flex items-center gap-1"><Phone size={12} fill="currentColor" /> 022-2785627</span>
           <span className="flex items-center gap-1"><Mail size={12} /> admin@alamanahlembang.sch.id</span>
        </div>
        <div className="flex gap-2 text-[#8BC53F]">
           <Facebook size={14} fill="currentColor" />
           <Instagram size={14} />
           <Youtube size={14} />
        </div>
      </div>

      {/* Main Header */}
      <header className="relative w-full p-4 flex justify-between items-center bg-white">
        
        {/* Left: School & Mosque Identity */}
        <div className="flex items-center gap-6 z-10 pl-2">
           
           {/* AIS LOGO IMAGE */}
           <div className="flex items-center">
             <img 
               src="/logoais.png" 
               alt="AIS Al-Amanah Islamic School" 
               className="h-16 md:h-20 object-contain"
               onError={(e) => {
                 // Fallback if image not found
                 e.currentTarget.style.display = 'none';
                 e.currentTarget.parentElement?.classList.add('fallback-mode');
               }}
             />
             {/* Fallback Text (Hidden if image loads) */}
             <div className="hidden fallback-text text-[#1D2B57] font-bold text-2xl">
               AIS AL-AMANAH
             </div>
           </div>
           
           {/* Vertical Divider */}
           <div className="h-16 w-0.5 bg-gray-200 mx-2 hidden md:block"></div>

           {/* Mosque Identity IMAGE */}
           <div className="flex items-center gap-4">
              <img 
                 src="/logo masjid.jpg" 
                 alt="Logo Masjid" 
                 className="h-14 md:h-16 w-14 md:w-16 object-cover rounded-full shadow-md"
                 onError={(e) => {
                   e.currentTarget.style.display = 'none';
                 }}
              />
              
              <div className="flex flex-col justify-center">
                 <h2 className="text-2xl font-bold text-[#1D2B57] tracking-tight uppercase leading-tight">
                   {mosqueName}
                 </h2>
                 <p className="text-sm text-gray-500 font-medium tracking-wide">
                   {mosqueAddress}
                 </p>
              </div>
           </div>
        </div>

        {/* Right: Clock & Date */}
        <div className="flex flex-col items-end z-10 text-right">
          <div className="bg-[#1D2B57] text-white px-5 py-2 rounded-xl shadow-lg border-b-4 border-[#8BC53F]">
             <div className="text-6xl font-bold font-mono tracking-tighter leading-none">
               {format(now, 'HH:mm:ss')}
             </div>
          </div>
          <div className="flex items-center gap-2 mt-2 font-bold text-[#1D2B57] text-base">
             <span>{format(now, 'EEEE, d MMMM yyyy', { locale: id })}</span>
             <span className="w-1.5 h-1.5 rounded-full bg-[#8BC53F]"></span>
             <span className="text-[#8BC53F]">{hijriDate}</span>
          </div>
        </div>
      </header>
      
      {/* Bottom Accent Line */}
      <div className="h-2 w-full flex">
         <div className="w-1/2 bg-[#8BC53F]"></div>
         <div className="w-1/2 bg-[#1D2B57]"></div>
      </div>
    </div>
  );
};
