import React from 'react';
import { cn } from '../lib/utils';

interface PrayerCardProps {
  name: string;
  time: string;
  isActive?: boolean;
  isNext?: boolean;
}

export const PrayerCard: React.FC<PrayerCardProps> = ({ name, time, isActive, isNext }) => {
  // Color mapping based on prayer name (approximate)
  const colors: Record<string, string> = {
    'Subuh': 'bg-teal-700',
    'Syuruq': 'bg-sky-600',
    'Dzuhur': 'bg-yellow-600',
    'Ashar': 'bg-orange-600',
    'Maghrib': 'bg-red-700',
    'Isya': 'bg-indigo-700',
  };

  const baseColor = colors[name] || 'bg-gray-700';

  return (
    <div className={cn(
      "relative overflow-hidden rounded-xl shadow-lg transition-all duration-500",
      baseColor,
      isActive && "ring-4 ring-white scale-105 z-10",
      isNext && "ring-2 ring-yellow-400"
    )}>
      <div className="p-4 flex flex-col items-center justify-center h-full text-white">
        <span className="text-xs uppercase font-bold tracking-widest opacity-80 mb-1">{name}</span>
        <span className="text-4xl font-bold tracking-tighter">{time}</span>
      </div>
    </div>
  );
};
