import React, { useState, useEffect } from 'react';
import { Header } from '../components/Header';
import { PrayerGrid } from '../components/PrayerGrid';
import { Countdown } from '../components/Countdown';
import { ContentArea } from '../components/ContentArea';
import { RunningText } from '../components/RunningText';
import { StatusOverlay, PrayerStatus } from '../components/StatusOverlay';
import { InfaqCard } from '../components/InfaqCard'; 
import { usePrayerTimes } from '../hooks/usePrayerTimes';
import { useSettingsStore } from '../store/useSettingsStore';
import { useClock } from '../hooks/useClock';
import { differenceInSeconds } from 'date-fns';

import { Settings, Bell, Timer, RotateCcw } from 'lucide-react'; 
import { useNavigate } from 'react-router-dom';

const PRAYER_NAMES: Record<string, string> = {
  fajr: 'Subuh',
  sunrise: 'Syuruq',
  dhuhr: 'Dzuhur',
  asr: 'Ashar',
  maghrib: 'Maghrib',
  isha: 'Isya',
};

export const Home: React.FC = () => {
  const navigate = useNavigate();
  const now = useClock();
  const { today } = usePrayerTimes();
  const { iqamahDuration, iqamahDurationSubuh, prayerDuration } = useSettingsStore();
  
  const [status, setStatus] = useState<PrayerStatus>('normal');
  const [activePrayer, setActivePrayer] = useState('');
  const [iqamahCountdown, setIqamahCountdown] = useState(0);

  // Manual Test Mode State
  const [manualStatus, setManualStatus] = useState<PrayerStatus | null>(null);

  useEffect(() => {
    // If Manual Mode is active, skip automatic calculation
    if (manualStatus) {
      setStatus(manualStatus);
      if (manualStatus === 'iqamah') {
        // Simple countdown simulation for test mode
        setIqamahCountdown(prev => (prev > 0 ? prev - 1 : 10)); // Loop 10s for test
      }
      if (!activePrayer) setActivePrayer('Dzuhur (Test)');
      return;
    }

    const prayers = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha']; 
    let newStatus: PrayerStatus = 'normal';
    let currentPrayerName = '';
    let iqamahSec = 0;

    for (const prayer of prayers) {
      const time = today.timeForPrayer(prayer as any);
      if (!time) continue;

      const diff = differenceInSeconds(now, time);
      
      // Determine Iqamah Duration based on Prayer
      // If Subuh (fajr), use iqamahDurationSubuh, else use generic iqamahDuration
      const currentDuration = prayer === 'fajr' ? iqamahDurationSubuh : iqamahDuration;

      // Adzan: 0 to 2 minutes (120s)
      if (diff >= 0 && diff < 120) {
        newStatus = 'adzan';
        currentPrayerName = PRAYER_NAMES[prayer];
        break;
      }
      
      // Iqamah: 2 min to (2 min + currentDuration)
      const iqamahStart = 120;
      const iqamahEnd = iqamahStart + (currentDuration * 60);
      
      if (diff >= iqamahStart && diff < iqamahEnd) {
        newStatus = 'iqamah';
        currentPrayerName = PRAYER_NAMES[prayer];
        iqamahSec = iqamahEnd - diff;
        break;
      }

      // Sholat: iqamahEnd to (iqamahEnd + prayerDuration min)
      const sholatEnd = iqamahEnd + (prayerDuration * 60);
      if (diff >= iqamahEnd && diff < sholatEnd) {
        newStatus = 'sholat';
        currentPrayerName = PRAYER_NAMES[prayer];
        break;
      }
    }

    setStatus(newStatus);
    setActivePrayer(currentPrayerName);
    setIqamahCountdown(iqamahSec);

  }, [now, today, iqamahDuration, iqamahDurationSubuh, prayerDuration, manualStatus]);

  // Handler for Test Buttons
  const toggleTestAdzan = () => {
    setManualStatus('adzan');
    setActivePrayer('Dzuhur (Test)');
  };

  const toggleTestIqamah = () => {
    setManualStatus('iqamah');
    setActivePrayer('Dzuhur (Test)');
    setIqamahCountdown(60); // Start 60s countdown
  };

  const resetTest = () => {
    setManualStatus(null);
    setActivePrayer('');
  };

  return (
    // Main Container
    <div className="h-screen w-screen flex flex-col overflow-hidden font-sans bg-gray-100 relative">
      <StatusOverlay status={status} prayerName={activePrayer} iqamahCountdown={iqamahCountdown} />

      {/* Header Section */}
      <Header />

      {/* Main Content Area */}
      <main className="flex-1 flex overflow-hidden p-4 gap-4 min-h-0">
        {/* Left: Content (Video/Image) - Takes 65% width */}
        <div className="flex-[2] relative rounded-3xl overflow-hidden shadow-2xl bg-black border border-gray-800">
          <ContentArea />
        </div>

        {/* Right: Info Panel - Takes 35% width */}
        <div className="flex-1 flex flex-col gap-4 overflow-hidden">
          {/* Countdown Card */}
          <div className="flex-none">
             <Countdown />
          </div>
          
          {/* Infaq Card */}
          <div className="flex-1 overflow-hidden flex flex-col justify-end min-h-0">
             <InfaqCard />
          </div>
        </div>
      </main>

      {/* Bottom: Prayer Grid */}
      <div className="px-2 mb-2">
        <PrayerGrid />
      </div>

      {/* Footer: Running Text */}
      <div className="flex-none relative z-20 overflow-hidden shadow-[0_-5px_10px_rgba(0,0,0,0.3)]">
        <RunningText />
      </div>

      {/* Control Buttons Group (Bottom Right) */}
      <div className="fixed bottom-4 right-4 z-50 flex items-center gap-2">
        {/* Test Controls - Always visible for easier access on TV/Touch */}
        <div className="flex gap-2">
          <button 
            onClick={resetTest}
            title="Reset to Auto"
            className="p-3 bg-gray-800 text-white rounded-full shadow-lg hover:bg-gray-700 border border-gray-600 active:scale-95 transition-transform"
          >
            <RotateCcw size={20} />
          </button>
          <button 
            onClick={toggleTestAdzan}
            title="Test Adzan"
            className="p-3 bg-mosque-gold text-white rounded-full shadow-lg hover:bg-yellow-600 border border-yellow-400 active:scale-95 transition-transform"
          >
            <Bell size={20} />
          </button>
          <button 
            onClick={toggleTestIqamah}
            title="Test Iqamah"
            className="p-3 bg-mosque-green text-white rounded-full shadow-lg hover:bg-green-700 border border-green-500 active:scale-95 transition-transform"
          >
            <Timer size={20} />
          </button>
        </div>

        {/* Settings Button */}
        <button 
          onClick={() => navigate('/settings')}
          className="p-3 bg-white/20 hover:bg-mosque-green text-gray-500 hover:text-white rounded-full transition-all backdrop-blur-sm border border-white/10 shadow-lg"
          title="Settings"
        >
          <Settings size={20} />
        </button>
      </div>
    </div>
  );
};
