import React, { useEffect, useState } from 'react';
import { usePrayerTimes } from '../hooks/usePrayerTimes';
import { useClock } from '../hooks/useClock';
import { differenceInSeconds } from 'date-fns';
import { cn } from '../lib/utils';

const PRAYER_NAMES: Record<string, string> = {
  fajr: 'Subuh',
  sunrise: 'Syuruq',
  dhuhr: 'Dzuhur',
  asr: 'Ashar',
  maghrib: 'Maghrib',
  isha: 'Isya',
};

export const Countdown: React.FC = () => {
  const { nextPrayer } = usePrayerTimes();
  const now = useClock();
  const [timeLeft, setTimeLeft] = useState(0);

  useEffect(() => {
    if (nextPrayer?.time) {
      const diff = differenceInSeconds(nextPrayer.time, now);
      setTimeLeft(diff > 0 ? diff : 0);
    }
  }, [now, nextPrayer]);

  if (!nextPrayer) return null;

  const hours = Math.floor(timeLeft / 3600);
  const minutes = Math.floor((timeLeft % 3600) / 60);
  const seconds = timeLeft % 60;

  const isUrgent = timeLeft < 600; // Less than 10 minutes

  return (
    <div
      className={cn(
        'flex flex-col items-center justify-center p-8 rounded-3xl shadow-xl transition-all duration-500 border relative overflow-hidden group',
        isUrgent 
          ? 'bg-gradient-to-br from-red-600 to-red-700 text-white border-red-500' 
          : 'bg-gradient-to-br from-emerald-50 to-teal-100 text-mosque-dark border-emerald-200'
      )}
    >
      {/* Background decoration */}
      <div className={cn(
        "absolute -right-10 -top-10 w-40 h-40 rounded-full opacity-20 blur-2xl",
        isUrgent ? "bg-white" : "bg-emerald-400"
      )}></div>
      <div className={cn(
        "absolute -left-10 -bottom-10 w-40 h-40 rounded-full opacity-20 blur-2xl",
        isUrgent ? "bg-white" : "bg-mosque-gold"
      )}></div>

      <h3 className={cn(
        "text-xl font-bold uppercase tracking-[0.2em] mb-4 relative z-10",
        isUrgent ? "text-red-100" : "text-emerald-800"
      )}>
        Menuju {PRAYER_NAMES[nextPrayer.name] || nextPrayer.name}
      </h3>
      
      <div className="flex items-baseline font-mono tracking-tighter relative z-10">
        {hours > 0 && (
          <>
            <div className="flex flex-col items-center">
              <span className="text-7xl md:text-8xl font-bold leading-none">{String(hours).padStart(2, '0')}</span>
              <span className="text-sm font-sans font-medium opacity-50 mt-1">JAM</span>
            </div>
            <span className="text-6xl mx-2 opacity-30 -translate-y-4">:</span>
          </>
        )}
        
        <div className="flex flex-col items-center">
          <span className="text-7xl md:text-8xl font-bold leading-none">{String(minutes).padStart(2, '0')}</span>
          <span className="text-sm font-sans font-medium opacity-50 mt-1">MENIT</span>
        </div>
        
        <span className="text-6xl mx-2 opacity-30 -translate-y-4 animate-pulse">:</span>
        
        <div className="flex flex-col items-center">
          <span className={cn(
            "text-7xl md:text-8xl font-bold leading-none w-[1.5em] text-center",
            isUrgent ? "text-white" : "text-mosque-gold"
          )}>
            {String(seconds).padStart(2, '0')}
          </span>
          <span className="text-sm font-sans font-medium opacity-50 mt-1">DETIK</span>
        </div>
      </div>
    </div>
  );
};
