import React from 'react';
import { usePrayerTimes } from '../hooks/usePrayerTimes';
import { PrayerCard } from './PrayerCard';
import { format } from 'date-fns';

const PRAYER_NAMES: Record<string, string> = {
  fajr: 'Subuh',
  sunrise: 'Syuruq',
  dhuhr: 'Dzuhur',
  asr: 'Ashar',
  maghrib: 'Maghrib',
  isha: 'Isya',
};

const ORDERED_PRAYERS = ['fajr', 'sunrise', 'dhuhr', 'asr', 'maghrib', 'isha'];

export const PrayerGrid: React.FC = () => {
  const { today, currentPrayer, nextPrayer } = usePrayerTimes();

  return (
    <div className="grid grid-cols-6 gap-6 px-8 mt-2 pb-4">
      {ORDERED_PRAYERS.map((key) => {
        const time = today.timeForPrayer(key as any);
        const isActive = currentPrayer === key;
        const isNext = nextPrayer?.name === key && !nextPrayer.isTomorrow;

        return (
          <PrayerCard
            key={key}
            name={PRAYER_NAMES[key]}
            time={time ? format(time, 'HH:mm') : '--:--'}
            isActive={isActive}
            isNext={isNext}
          />
        );
      })}
    </div>
  );
};
